AND i.customer = #{query.customer}
UNION ALL
SELECT a.name AS name, '付款单' AS type, f.name AS frame, s.name AS customer, o.time AS time, o.number AS number, 0 AS income, oi.money AS expend, a.balance AS balance, o.user AS user, oi.data AS data FROM omy o JOIN omy_info oi ON o.id = oi.pid JOIN account a ON oi.account = a.id JOIN supplier s ON o.supplier = s.id JOIN frame f ON o.frame = f.id WHERE 1 = 1
AND o.supplier = #{query.supplier}
) AS t WHERE 1=1
AND t.name = #{query.account}
AND t.time >= #{query.startTime}
AND t.time <= #{query.endTime}
AND t.user = #{query.user}
ORDER BY t.time DESC
